"use client";

import Link from "next/link";
import { useMemo, useState } from "react";

type AdminNote = {
  internal_status?: string | null;
  billing_status?: string | null;
  next_step?: string | null;
  follow_up_date?: string | null;
  markus_included?: boolean | null;
};

type ShowRow = {
  id: string;
  token: string;
  artist: string | null;
  program: string | null;
  show_date: string | null;
  venue: string | null;
  city: string | null;
  start_time: string | null;
  entry_time: string | null;
  show_details?: Record<string, string | null>[] | null;
  show_files?: { id: string; file_name?: string | null; file_type?: string | null }[] | null;
  show_admin_notes?: AdminNote[] | null;
};

export default function AdminClient({
  shows,
  createShowAction,
  deleteShowAction,
}: {
  shows: ShowRow[];
  createShowAction: (formData: FormData) => void | Promise<void>;
  deleteShowAction: (formData: FormData) => void | Promise<void>;
}) {
  const [query, setQuery] = useState("");
  const [filter, setFilter] = useState("aktiv");
  const [year, setYear] = useState("alle");
  const [showCreate, setShowCreate] = useState(false);

  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const years = Array.from(
    new Set(shows.map((s) => s.show_date?.slice(0, 4)).filter(Boolean))
  ).sort();

  const followUps = shows.filter((show) => {
    const admin = show.show_admin_notes?.[0];
    if (!admin?.follow_up_date) return false;
    const date = new Date(admin.follow_up_date);
    return date <= today && !["abgeschlossen", "archiv"].includes(admin.internal_status || "");
  });

  const rows = useMemo(() => {
    return shows.filter((show) => {
      const status = getStatus(show);
      const admin = show.show_admin_notes?.[0] || {};
      const date = show.show_date ? new Date(show.show_date) : null;
      const isPast = date ? date < today : false;
      const isFuture = date ? date >= today : true;
      const isArchived =
        admin.internal_status === "abgeschlossen" ||
        admin.internal_status === "archiv";

      const text = [show.artist, show.program, show.venue, show.city, show.token]
        .join(" ")
        .toLowerCase();

      const matchesSearch = text.includes(query.toLowerCase());
      const matchesYear = year === "alle" || show.show_date?.startsWith(year);

      const matchesFilter =
        filter === "alle" ||
        (filter === "aktiv" && !isArchived) ||
        (filter === "kommend" && isFuture && !isArchived) ||
        (filter === "vergangen_offen" && isPast && !isArchived) ||
        (filter === "abrechnung" && isPast && admin.billing_status !== "bezahlt") ||
        (filter === "followup" && !!admin.follow_up_date && new Date(admin.follow_up_date) <= today) ||
        (filter === "markus" && admin.markus_included === true) ||
        (filter === "archiv" && isArchived) ||
        status.key === filter;

      return matchesSearch && matchesYear && matchesFilter;
    });
  }, [shows, query, filter, year]);

  const grouped = groupByMonth(rows);

  return (
    <main className="min-h-screen bg-[#fbf7ef] p-6 text-zinc-950">
      <div className="mx-auto max-w-7xl">
        <header className="mb-8 flex flex-col gap-5 md:flex-row md:items-end md:justify-between">
          <div>
            <p className="text-xs font-black uppercase tracking-[0.25em] text-zinc-500">
              primakavi
            </p>
            <h1 className="mt-2 text-5xl font-black tracking-tight">
              Show Admin
            </h1>
            <p className="mt-3 text-sm font-semibold text-zinc-600">
              Shows verwalten, Akten öffnen, Portale verschicken.
            </p>
          </div>

          <div className="flex flex-wrap gap-3">
            <Link
              href="/markus"
              target="_blank"
              className="rounded-3xl bg-zinc-950 px-6 py-4 font-black text-white shadow-xl"
            >
              Markus-Ansicht →
            </Link>

            <button
              type="button"
              onClick={() => setShowCreate((prev) => !prev)}
              className="rounded-3xl bg-gradient-to-r from-pink-400 to-orange-400 px-6 py-4 font-black text-white shadow-xl transition hover:scale-[1.02]"
            >
              Neue Show +
            </button>
          </div>
        </header>

        {followUps.length > 0 && (
          <section className="mb-6 rounded-[2rem] bg-amber-100 p-5 shadow-xl shadow-zinc-200/70">
            <div className="flex items-center justify-between gap-4">
              <div>
                <h2 className="text-2xl font-black">🔔 Heute fällig / überfällig</h2>
                <p className="mt-1 text-sm font-bold text-zinc-600">
                  {followUps.length} Wiedervorlage(n)
                </p>
              </div>
              <button
                type="button"
                onClick={() => setFilter("followup")}
                className="rounded-full bg-zinc-950 px-5 py-3 text-sm font-black text-white"
              >
                Anzeigen →
              </button>
            </div>
          </section>
        )}

        {showCreate && (
          <section className="mb-8 rounded-[2rem] bg-white p-6 shadow-xl shadow-zinc-200/70">
            <h2 className="text-2xl font-black">Neue Show anlegen</h2>

            <form action={createShowAction} className="mt-5 grid gap-4 md:grid-cols-4">
              <Input name="artist" label="Artist" defaultValue="Sonja Gründemann" />
              <Input name="program" label="Programm" placeholder="Jetzt mal Tacheles" />
              <Input name="show_date" label="Datum" type="date" />
              <Input name="venue" label="Location" placeholder="Brakula" />
              <Input name="city" label="Stadt" placeholder="Hamburg" />
              <Input name="entry_time" label="Einlass" placeholder="19:00 Uhr" />
              <Input name="start_time" label="Showbeginn" placeholder="20:00 Uhr" />

              <button
                type="submit"
                className="self-end rounded-2xl bg-zinc-950 px-5 py-4 font-black text-white shadow-lg"
              >
                Erstellen →
              </button>
            </form>
          </section>
        )}

        <section className="mb-6 rounded-[2rem] bg-white p-5 shadow-xl shadow-zinc-200/70">
          <div className="grid gap-4 lg:grid-cols-[1fr_auto]">
            <input
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Suche nach Location, Stadt, Programm..."
              className="h-14 rounded-2xl border border-zinc-200 bg-zinc-50 px-5 text-sm font-semibold outline-none focus:border-pink-300 focus:ring-4 focus:ring-pink-100"
            />

            <select
              value={year}
              onChange={(e) => setYear(e.target.value)}
              className="h-14 rounded-2xl border border-zinc-200 bg-zinc-50 px-5 text-sm font-black outline-none"
            >
              <option value="alle">Alle Jahre</option>
              {years.map((y) => (
                <option key={y} value={y}>
                  {y}
                </option>
              ))}
            </select>
          </div>

          <div className="mt-4 flex flex-wrap gap-2">
            {[
              ["aktiv", "Aktiv"],
              ["followup", "Wiedervorlage"],
              ["kommend", "Kommend"],
              ["vergangen_offen", "Vergangen offen"],
              ["abrechnung", "Abrechnung offen"],
              ["markus", "Markus dabei"],
              ["fertig", "Fertig"],
              ["arbeit", "In Arbeit"],
              ["archiv", "Archiv"],
              ["alle", "Alle"],
            ].map(([key, label]) => (
              <button
                key={key}
                type="button"
                onClick={() => setFilter(key)}
                className={`rounded-full px-4 py-2 text-sm font-black transition ${
                  filter === key
                    ? "bg-zinc-950 text-white"
                    : "bg-zinc-100 text-zinc-700 hover:bg-zinc-200"
                }`}
              >
                {label}
              </button>
            ))}
          </div>
        </section>

        <section className="rounded-[2rem] bg-white p-5 shadow-xl shadow-zinc-200/70">
          {Object.entries(grouped).map(([month, monthShows]) => (
            <div key={month} className="mb-8 last:mb-0">
              <h2 className="mb-4 text-2xl font-black">{month}</h2>

              <div className="space-y-3">
                {monthShows.map((show) => {
                  const status = getStatus(show);
                  const admin = show.show_admin_notes?.[0] || {};
                  const details = show.show_details?.[0] || {};
                  const portalUrl = `${window.location.origin}/show/${show.token}`;

                  return (
                    <div
                      key={show.id}
                      className="relative grid gap-4 rounded-3xl bg-zinc-50 p-4 transition hover:bg-zinc-100 md:grid-cols-[120px_1fr_190px_340px] md:items-center"
                    >
                      <Link
                        href={`/admin/shows/${show.id}`}
                        className="absolute inset-0 rounded-3xl"
                        aria-label="Akte öffnen"
                      />

                      <div className="relative">
                        <p className="font-black">{formatDate(show.show_date)}</p>
                        <p className="text-xs font-bold text-zinc-500">
                          {show.start_time || "Uhrzeit offen"}
                        </p>
                      </div>

                      <div className="relative">
                        <p className="text-lg font-black">
                          {show.venue || "Location offen"}
                        </p>
                        <p className="text-sm font-semibold text-zinc-500">
                          {show.city || "Ort offen"} · {show.program || "Programm offen"}
                        </p>
                        {admin.markus_included && (
                          <p className="mt-1 text-xs font-black text-purple-700">
                            Markus dabei
                          </p>
                        )}
                      </div>

                      <div className="relative">
                        <span className={`rounded-full px-3 py-1 text-xs font-black ${status.className}`}>
                          {status.label}
                        </span>
                        {admin.billing_status && (
                          <p className="mt-2 text-xs font-bold text-zinc-500">
                            Abrechnung: {billingLabel(admin.billing_status)}
                          </p>
                        )}
                      </div>

                      <div className="relative z-10 flex flex-wrap justify-start gap-2 md:justify-end">
                        <Link
                          href={`/admin/shows/${show.id}`}
                          className="rounded-full bg-zinc-950 px-4 py-2 text-xs font-black text-white"
                        >
                          Akte →
                        </Link>

                        <button
                          type="button"
                          onClick={() => navigator.clipboard.writeText(portalUrl)}
                          className="rounded-full bg-purple-100 px-4 py-2 text-xs font-black text-purple-700"
                        >
                          Link kopieren
                        </button>

                        <a
                          href={makeMailto(show, details, portalUrl)}
                          className="rounded-full bg-pink-100 px-4 py-2 text-xs font-black text-pink-700"
                        >
                          Mail
                        </a>

                        <form
                          action={deleteShowAction}
                          onSubmit={(e) => {
                            const ok = window.confirm(
                              `Bist du sicher, dass du die Show "${show.venue || "ohne Location"}" löschen möchtest?`
                            );
                            if (!ok) e.preventDefault();
                          }}
                        >
                          <input type="hidden" name="show_id" value={show.id} />
                          <button
                            type="submit"
                            className="rounded-full bg-red-100 px-4 py-2 text-xs font-black text-red-700"
                          >
                            Löschen
                          </button>
                        </form>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          ))}

          {rows.length === 0 && (
            <div className="rounded-3xl bg-zinc-50 p-10 text-center">
              <p className="font-black">Keine Shows gefunden.</p>
            </div>
          )}
        </section>
      </div>
    </main>
  );
}

function makeMailto(
  show: ShowRow,
  details: Record<string, string | null>,
  portalUrl: string
) {
  const to = details.contact_email || "";
  const subject = `Veranstalterinfos Sonja Gründemann – ${formatDate(show.show_date)} ${show.venue || ""}`;

  const body = `Hallo${details.contact_name ? ` ${details.contact_name}` : ""},

hier finden Sie das Veranstalter-Portal für den Auftritt von Sonja Gründemann:

${portalUrl}

Wir haben die bekannten Rahmendaten bereits hinterlegt:
- Datum: ${formatDate(show.show_date)}
- Location: ${show.venue || "offen"}
- Stadt: ${show.city || "offen"}
- Programm: ${show.program || "offen"}
- Beginn: ${show.start_time || "offen"}

Bitte ergänzen Sie dort die noch offenen Informationen zu Ablauf, Technik, Anreise und Organisation.

Vielen Dank und herzliche Grüße
primakavi Booking`;

  return `mailto:${to}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
}

function getStatus(show: ShowRow) {
  const details = show.show_details?.[0] || {};
  const admin = show.show_admin_notes?.[0] || {};
  const date = show.show_date ? new Date(show.show_date) : null;
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const isPast = date ? date < today : false;

  if (admin.internal_status === "abgeschlossen") {
    return {
      key: "archiv",
      label: "✅ Abgeschlossen",
      className: "bg-emerald-100 text-emerald-700",
    };
  }

  if (admin.internal_status === "archiv") {
    return {
      key: "archiv",
      label: "📦 Archiv",
      className: "bg-zinc-200 text-zinc-700",
    };
  }

  if (isPast && admin.billing_status !== "bezahlt") {
    return {
      key: "arbeit",
      label: "💸 Abrechnung offen",
      className: "bg-orange-100 text-orange-700",
    };
  }

  const checks = [
    !!(details.program || show.program) && !!(details.event_date || show.show_date),
    !!details.contact_name && !!details.contact_email,
    !!details.entry_time && !!details.start_time,
    !!details.sound_system || !!details.tech_notes,
    !!details.contract_status || !!details.ticket_link,
    !!details.accommodation_type || !!details.travel_options,
    !!show.show_files?.length,
  ];

  const done = checks.filter(Boolean).length;

  if (done === checks.length) {
    return {
      key: "fertig",
      label: "🟢 Fertig",
      className: "bg-emerald-100 text-emerald-700",
    };
  }

  if (done >= checks.length - 2) {
    return {
      key: "fast",
      label: "🟡 Fast fertig",
      className: "bg-amber-100 text-amber-700",
    };
  }

  if (done >= 2) {
    return {
      key: "arbeit",
      label: "🟠 In Arbeit",
      className: "bg-orange-100 text-orange-700",
    };
  }

  return {
    key: "offen",
    label: "🔴 Offen",
    className: "bg-red-100 text-red-700",
  };
}

function billingLabel(value?: string | null) {
  const labels: Record<string, string> = {
    offen: "offen",
    rechnung_geschrieben: "geschrieben",
    rechnung_verschickt: "verschickt",
    bezahlt: "bezahlt",
  };

  return labels[value || ""] || value || "offen";
}

function groupByMonth(shows: ShowRow[]) {
  return shows.reduce<Record<string, ShowRow[]>>((acc, show) => {
    const label = monthLabel(show.show_date);
    acc[label] ||= [];
    acc[label].push(show);
    return acc;
  }, {});
}

function monthLabel(date?: string | null) {
  if (!date) return "Ohne Datum";
  const d = new Date(date);
  if (Number.isNaN(d.getTime())) return "Ohne Datum";

  return d.toLocaleDateString("de-DE", {
    month: "long",
    year: "numeric",
  });
}

function Input({
  name,
  label,
  type = "text",
  placeholder,
  defaultValue,
}: {
  name: string;
  label: string;
  type?: string;
  placeholder?: string;
  defaultValue?: string;
}) {
  return (
    <label className="grid gap-2 text-xs font-black text-zinc-700">
      {label}
      <input
        name={name}
        type={type}
        placeholder={placeholder}
        defaultValue={defaultValue}
        className="h-14 rounded-2xl border border-zinc-200 bg-zinc-50 px-4 text-sm font-semibold outline-none focus:border-pink-300 focus:ring-4 focus:ring-pink-100"
      />
    </label>
  );
}

function formatDate(date?: string | null) {
  if (!date) return "Datum offen";
  const d = new Date(date);
  if (Number.isNaN(d.getTime())) return date;

  return d.toLocaleDateString("de-DE", {
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
  });
}